import{_ as e,o as r,c as t,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"香港货币兑换","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"transfers-and-fx/hk-fx.md","filePath":"zh-CN/transfers-and-fx/hk-fx.md"}'),i={name:"transfers-and-fx/hk-fx.md"};function o(n,a,h,s,d,p){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="香港货币兑换" tabindex="-1">香港货币兑换 <a class="header-anchor" href="#香港货币兑换" aria-label="Permalink to &quot;香港货币兑换&quot;">​</a></h1><p>货币兑换是指证券账户内多种币种之间的相互兑换。为方便资金在港股、美股之间转换，长桥香港提供货币兑换功能。</p><h2 id="支持币种" tabindex="-1">支持币种 <a class="header-anchor" href="#支持币种" aria-label="Permalink to &quot;支持币种&quot;">​</a></h2><p>港元（HKD）、美元（USD）、离岸人民币（CNH）</p><p>注意：</p><ul><li>离岸人民币（CNH）只能作为来源货币兑出，可兑换为港元（HKD）或美元（USD）</li><li>不支持将 USD / HKD 兑换为 CNH</li><li>如港股公司行动产生 CNH，可自行兑换为 HKD 或 USD</li></ul><h2 id="手续费" tabindex="-1">手续费 <a class="header-anchor" href="#手续费" aria-label="Permalink to &quot;手续费&quot;">​</a></h2><p>免费（不收取手续费）</p><h2 id="兑换汇率" tabindex="-1">兑换汇率 <a class="header-anchor" href="#兑换汇率" aria-label="Permalink to &quot;兑换汇率&quot;">​</a></h2><p>由银行供应商提供的实时汇率，以实际兑换时的汇率为准。兑换页面展示的汇率仅供参考。</p><p>注意：频繁兑入兑出会存在汇率差。</p><h2 id="处理时间" tabindex="-1">处理时间 <a class="header-anchor" href="#处理时间" aria-label="Permalink to &quot;处理时间&quot;">​</a></h2><p>实时完成：交易日 08:00 AM - 次日 05:00 AM 提交的货币兑换预计实时完成（12 月 25 日和 1 月 1 日除外）。<br> 非实时完成：非交易日提交的货币兑换订单将在下一个交易日兑换开放时间完成。例如周日提交的订单将在周一 08:00 AM 之后完成。</p><p>长桥将在假期前发出特别通知，请留意相关公告。</p><h2 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 货币兑换，查看当日汇率，输入金额后即可兑换。</p><h2 id="用途限制与精度规则" tabindex="-1">用途限制与精度规则 <a class="header-anchor" href="#用途限制与精度规则" aria-label="Permalink to &quot;用途限制与精度规则&quot;">​</a></h2><ul><li>货币兑换功能仅用于交易结算，请勿用于货币投机，与交易无关的请求将被拒绝</li><li>兑换金额均四舍五入取整至小数点后两位</li></ul>',18)])])}const f=e(i,[["render",o]]);export{u as __pageData,f as default};
